# Category: serverless_security

import os
import json
import logging
import azure.functions as func
from azure.storage.blob import BlobServiceClient
from azure.cosmos import CosmosClient, PartitionKey
from azure.eventgrid import EventGridPublisherClient, CloudEvent
from azure.identity import DefaultAzureCredential

# --- Configuration ---
# Blob Storage
BLOB_STORAGE_ACCOUNT_URL = os.environ.get("BLOB_STORAGE_ACCOUNT_URL") # e.g., "https://<your_storage_account_name>.blob.core.windows.net"
BLOB_CONTAINER_NAME = os.environ.get("BLOB_CONTAINER_NAME")

# Cosmos DB
COSMOS_DB_ACCOUNT_URL = os.environ.get("COSMOS_DB_ACCOUNT_URL") # e.g., "https://<your_cosmos_account_name>.documents.azure.com:443/"
COSMOS_DB_DATABASE_NAME = os.environ.get("COSMOS_DB_DATABASE_NAME")
COSMOS_DB_CONTAINER_NAME = os.environ.get("COSMOS_DB_CONTAINER_NAME")
COSMOS_DB_PARTITION_KEY_PATH = os.environ.get("COSMOS_DB_PARTITION_KEY_PATH", "/id") # Default to /id

# Event Grid
EVENT_GRID_TOPIC_ENDPOINT = os.environ.get("EVENT_GRID_TOPIC_ENDPOINT") # e.g., "https://<your_event_grid_topic_name>.<region>.eventgrid.azure.net/api/events"

# --- Clients (initialized once per function app instance) ---
credential = DefaultAzureCredential()

blob_service_client = None
if BLOB_STORAGE_ACCOUNT_URL:
    blob_service_client = BlobServiceClient(account_url=BLOB_STORAGE_ACCOUNT_URL, credential=credential)
else:
    logging.warning("BLOB_STORAGE_ACCOUNT_URL is not set. Blob operations will be skipped.")

cosmos_client = None
cosmos_database = None
cosmos_container = None
if COSMOS_DB_ACCOUNT_URL and COSMOS_DB_DATABASE_NAME and COSMOS_DB_CONTAINER_NAME:
    try:
        cosmos_client = CosmosClient(url=COSMOS_DB_ACCOUNT_URL, credential=credential)
        cosmos_database = cosmos_client.get_database_client(COSMOS_DB_DATABASE_NAME)
        # Ensure database and container exist (for MVP, broad permissions allow creation)
        cosmos_database.create_if_not_exists()
        cosmos_container = cosmos_database.create_container_if_not_exists(
            id=COSMOS_DB_CONTAINER_NAME,
            partition_key=PartitionKey(path=COSMOS_DB_PARTITION_KEY_PATH)
        )
    except Exception as e:
        logging.error(f"Failed to initialize Cosmos DB client: {e}")
        cosmos_client = None # Disable Cosmos DB operations if initialization fails
else:
    logging.warning("Cosmos DB configuration (URL, DB Name, Container Name) is incomplete. Cosmos DB operations will be skipped.")

event_grid_publisher_client = None
if EVENT_GRID_TOPIC_ENDPOINT:
    event_grid_publisher_client = EventGridPublisherClient(endpoint=EVENT_GRID_TOPIC_ENDPOINT, credential=credential)
else:
    logging.warning("EVENT_GRID_TOPIC_ENDPOINT is not set. Event Grid notifications will be skipped.")

app = func.FunctionApp()

@app.blob_trigger(arg_name="inputblob", path=BLOB_CONTAINER_NAME + "/{name}",
                  connection="AzureWebJobsStorage") # AzureWebJobsStorage is used for the trigger's internal connection, not for the BlobServiceClient
def process_blob_function(inputblob: func.InputStream):
    logging.info(f"Python blob trigger function processed blob\n"
                 f"Name: {inputblob.name}\n"
                 f"Size: {inputblob.length} Bytes")

    blob_name = inputblob.name.split('/')[-1]
    processed_data = {}
    notification_event = None

    try:
        # --- 1. Process Blob Content ---
        blob_content = inputblob.read().decode('utf-8')
        logging.info(f"Content of {blob_name}:\n{blob_content[:200]}...") # Log first 200 chars

        # Example processing: Count words, simulate some analysis
        word_count = len(blob_content.split())
        processed_data = {
            "id": blob_name.replace('.', '-').lower(), # Cosmos DB id
            "blobName": blob_name,
            "blobUri": inputblob.uri,
            "sizeBytes": inputblob.length,
            "wordCount": word_count,
            "processingTimestamp": func.get_current_utc_timestamp().isoformat(),
            "status": "Processed"
        }
        logging.info(f"Successfully processed blob '{blob_name}'. Word count: {word_count}")

        # --- 2. Write Results to Cosmos DB ---
        if cosmos_container:
            try:
                cosmos_container.upsert_item(body=processed_data)
                logging.info(f"Results for '{blob_name}' written to Cosmos DB.")
                processed_data["cosmosDbStatus"] = "Success"
            except Exception as e:
                logging.error(f"Failed to write results for '{blob_name}' to Cosmos DB: {e}")
                processed_data["cosmosDbStatus"] = "Failed"
                processed_data["cosmosDbError"] = str(e)
        else:
            logging.warning(f"Cosmos DB client not initialized. Skipping Cosmos DB write for '{blob_name}'.")
            processed_data["cosmosDbStatus"] = "Skipped"

        # --- 3. Prepare Event Grid Notification ---
        notification_event = CloudEvent(
            source=inputblob.uri,
            type="com.example.blobProcessed",
            data={
                "blobName": blob_name,
                "blobUri": inputblob.uri,
                "status": processed_data.get("status", "Processed"),
                "wordCount": processed_data.get("wordCount"),
                "processingTimestamp": processed_data.get("processingTimestamp"),
                "cosmosDbStatus": processed_data.get("cosmosDbStatus")
            }
        )

    except Exception as e:
        logging.error(f"Error processing blob '{blob_name}': {e}")
        processed_data = {
            "id": blob_name.replace('.', '-').lower(),
            "blobName": blob_name,
            "blobUri": inputblob.uri,
            "sizeBytes": inputblob.length,
            "processingTimestamp": func.get_current_utc_timestamp().isoformat(),
            "status": "Failed",
            "errorMessage": str(e)
        }
        if cosmos_container:
            try:
                cosmos_container.upsert_item(body=processed_data)
                logging.info(f"Error details for '{blob_name}' written to Cosmos DB.")
            except Exception as cosmos_e:
                logging.error(f"Failed to write error details for '{blob_name}' to Cosmos DB: {cosmos_e}")

        notification_event = CloudEvent(
            source=inputblob.uri,
            type="com.example.blobProcessingFailed",
            data={
                "blobName": blob_name,
                "blobUri": inputblob.uri,
                "status": "Failed",
                "errorMessage": str(e),
                "processingTimestamp": processed_data.get("processingTimestamp")
            }
        )

    # --- 4. Send Event Grid Notification ---
    if event_grid_publisher_client and notification_event:
        try:
            event_grid_publisher_client.send([notification_event])
            logging.info(f"Event Grid notification sent for '{blob_name}'. Event Type: {notification_event.type}")
        except Exception as e:
            logging.error(f"Failed to send Event Grid notification for '{blob_name}': {e}")
    else:
        logging.warning(f"Event Grid client not initialized or no event to send. Skipping notification for '{blob_name}'.")

